import { Project } from './project';
import { TaskPriority } from './task-priority';
import { TaskStatusDetail } from './task-status-detail';

export class Task {
  taskID: number | any;
  taskName: string | any;
  description: string | any;
  createdOn: string | any;
  projectID: number | any;
  createdBy: string | any;
  assignedTo: string | any;
  taskPriorityID: number | any;
  lastUpdatedOn: string | any;
  currentStatus: string | any;
  taskStatusID: number | any;
  project: Project | any;
  createdByUser: any;
  assignedToUser: any;
  taskPriority: TaskPriority | any;
  taskStatusDetails: TaskStatusDetail | any;

  constructor() {
    this.taskID = null;
    this.taskName = null;
    this.description = null;
    this.createdOn = null;
    this.projectID = null;
    this.createdBy = null;
    this.assignedTo = null;
    this.taskPriorityID = null;
    this.lastUpdatedOn = null;
    this.currentStatus = null;
    this.taskStatusID = null;
    this.project = null;
    this.createdByUser = null;
    this.assignedToUser = null;
    this.taskPriority = null;
    this.taskStatusDetails = null;
  }
}
